// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
interface ViewProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  windUnit: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
  forecastTitle?: string;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  return {
    city: props.city,
    temperature: props.temperature,
    condition: props.condition,
    humidity: props.humidity,
    windSpeed: props.windSpeed,
    unit: props.unit,
    windUnit: 'm/s',
    forecast: props.forecast || [],
    forecastTitle: '5-Day Forecast',
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // Helper: get weather icon/emoji based on condition string
  const getWeatherIcon = (condition: string): string => {
    const lower = condition.toLowerCase();
    if (lower.includes('sunny') || lower.includes('clear')) return 'sun';
    if (lower.includes('cloudy') || lower.includes('cloud')) return 'cloud';
    if (lower.includes('rainy') || lower.includes('rain')) return 'cloud-rain';
    if (lower.includes('snowy') || lower.includes('snow')) return 'snowflake';
    if (lower.includes('thunder') || lower.includes('storm')) return 'cloud-lightning';
    if (lower.includes('windy') || lower.includes('wind')) return 'wind';
    if (lower.includes('foggy') || lower.includes('fog')) return 'cloud-fog';
    return 'cloud';
  };

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>{props.city}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Current weather in {props.city}
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24}>
            {/* Temperature & Condition Row */}
            <Row align="center" justify="between" gap={32}>
              <Stack gap={16} align="start">
                {/* Large Temperature Display */}
                <Stack gap={4} align="start">
                  <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)">
                    {props.temperature}°{props.unit}
                  </Text>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
                    {props.condition}
                  </Text>
                </Stack>
              </Stack>

              {/* Weather Icon/Emoji */}
              <Icon name={getWeatherIcon(props.condition)} size={96} color="var(--ggui-color-primary-600, #0284c7)" />
            </Row>

            <Divider orientation="horizontal" margin={12} />

            {/* Humidity & Wind Speed */}
            <Row gap={24} justify="start" align="center">
              <Stack gap={8} align="start">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Humidity
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.humidity}%
                </Text>
              </Stack>

              <Stack gap={8} align="start">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Wind Speed
                </Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {props.windSpeed} {props.windUnit}
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST STRIP */}
         {/* 5-DAY FORECAST STRIP */}
         <Stack gap={12}>
           <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
             {props.forecastTitle || '5-Day Forecast'}
           </Heading>
          <Row gap={12} wrap align="stretch" justify="start">
            {props.forecast.map((day, index) => (
              <Card
                key={index}
                padding={16}
                shadow="sm"
                radius="md"
                style={{
                  flex: '0 1 calc(20% - 10px)',
                  minWidth: '120px',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  gap: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)" align="center">
                  {day.day || `Day ${index + 1}`}
                </Text>

                 <Icon name={day.icon || getWeatherIcon('clear')} size={32} />
                 <Stack gap={2} align="center">
                   <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                     {day.high !== undefined ? `${day.high}°${props.unit}` : 'N/A'}
                   </Text>
                   <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                     {day.low !== undefined ? `${day.low}°${props.unit}` : 'N/A'}
                   </Text>
                  </Stack>
              </Card>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

