// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  // Step state
  currentStep: number;
  totalSteps: number;

  // Form data
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;

  // Validation
  nameError: string;
  emailError: string;

  // Handlers
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: string) => void;
  onFeatureToggle: (feature: string) => void;
  onCommentsChange: (value: string) => void;
  onNext: () => void;
  onBack: () => void;
  onSubmit: () => void;

  // Options from props
  featureOptions: string[];
  satisfactionLabels: string[];
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState(1);

  // Form state
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  const TOTAL_STEPS = 4;

  // Validation functions
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  const isStep1Valid = useCallback(() => {
    const nameValid = name.trim().length > 0;
    const emailValid = email.trim().length > 0 && validateEmail(email);

    if (!nameValid) {
      setNameError('Name is required');
    } else {
      setNameError('');
    }

    if (!emailValid) {
      if (email.trim().length === 0) {
        setEmailError('Email is required');
      } else {
        setEmailError('Please enter a valid email format');
      }
    } else {
      setEmailError('');
    }

    return nameValid && emailValid;
  }, [name, email, validateEmail]);

  // Handlers
  const handleNameChange = useCallback((value: string) => {
    setName(value);
    if (value.trim().length === 0) {
      setNameError('Name is required');
    } else {
      setNameError('');
    }
  }, []);

  const handleEmailChange = useCallback((value: string) => {
    setEmail(value);
    if (value.trim().length === 0) {
      setEmailError('Email is required');
    } else if (!validateEmail(value)) {
      setEmailError('Please enter a valid email format');
    } else {
      setEmailError('');
    }
  }, [validateEmail]);

  const handleSatisfactionChange = useCallback((value: string) => {
    setSatisfaction(parseInt(value, 10));
  }, []);

  const handleFeatureToggle = useCallback((feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  }, []);

  const handleCommentsChange = useCallback((value: string) => {
    if (value.length <= 500) {
      setComments(value);
    }
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (!isStep1Valid()) return;
    }
    if (currentStep < TOTAL_STEPS) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [currentStep, isStep1Valid]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const submit = useAction<ActionSubmitPayload>('submitSurvey');

  const handleSubmit = useCallback(() => {
    submit({
      name,
      email,
      satisfaction,
      features,
      comments,
    });
  }, [name, email, satisfaction, features, comments, submit]);

  return {
    currentStep,
    totalSteps: TOTAL_STEPS,
    name,
    email,
    satisfaction,
    features,
    comments,
    nameError,
    emailError,
    onNameChange: handleNameChange,
    onEmailChange: handleEmailChange,
    onSatisfactionChange: handleSatisfactionChange,
    onFeatureToggle: handleFeatureToggle,
    onCommentsChange: handleCommentsChange,
    onNext: handleNext,
    onBack: handleBack,
    onSubmit: handleSubmit,
    featureOptions: props.featureOptions,
    satisfactionLabels: props.satisfactionLabels,
  };
  };

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const [showReview, setShowReview] = useState(false);

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  const renderStep = () => {
    switch (props.currentStep) {
      case 1:
        return (
          <Stack gap={16}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
              Tell us about yourself
            </Text>
            <Input
              label="Full Name"
              value={props.name}
              onChange={props.onNameChange}
              error={props.nameError}
              required
              placeholder="Enter your name"
            />
            <Input
              label="Email Address"
              type="email"
              value={props.email}
              onChange={props.onEmailChange}
              error={props.emailError}
              required
              placeholder="Enter your email"
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={16}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
              How satisfied are you with our service?
            </Text>
            <RadioGroup
              label="Satisfaction Rating"
              value={String(props.satisfaction)}
              onChange={props.onSatisfactionChange}
              options={satisfactionOptions}
              direction="vertical"
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
              Which features are you interested in?
            </Text>
            <Stack gap={8}>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={props.features.includes(feature)}
                  onChange={() => props.onFeatureToggle(feature)}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 4:
        return (
          <Stack gap={16}>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)">
              Any additional comments? (Optional, max 500 characters)
            </Text>
            <TextArea
              label="Comments"
              value={props.comments}
              onChange={props.onCommentsChange}
              placeholder="Share your thoughts..."
              rows={6}
              maxLength={500}
              showCount
            />
          </Stack>
        );
      default:
        return null;
    }
  };

  const renderReview = () => (
    <Stack gap={16}>
      <Heading level={2}>Review Your Answers</Heading>
      <Card shadow="sm" padding={16}>
        <Stack gap={12}>
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
            <Text color="var(--ggui-color-onSurface, #18181b)">{props.name}</Text>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
            <Text color="var(--ggui-color-onSurface, #18181b)">{props.email}</Text>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
            <Text color="var(--ggui-color-onSurface, #18181b)">
              {props.satisfaction && `${props.satisfaction} - ${props.satisfactionLabels[parseInt(props.satisfaction, 10) - 1]}`}
            </Text>
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features of Interest</Text>
            {props.features.length > 0 ? (
              <Stack gap={4} direction="horizontal" wrap>
                {props.features.map((feature) => (
                  <Badge key={feature} variant="primary" size="sm">
                    {feature}
                  </Badge>
                ))}
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">None selected</Text>
            )}
          </Box>
          <Divider />
          <Box>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
            <Text color="var(--ggui-color-onSurface, #18181b)">
              {props.comments || '(No comments provided)'}
            </Text>
          </Box>
        </Stack>
      </Card>
    </Stack>
  );

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={1}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {props.currentStep} of {props.totalSteps}
          </Text>
        </Stack>

        {/* PROGRESS BAR */}
        <Progress
          value={props.currentStep}
          max={props.totalSteps}
          variant="default"
          size="md"
          showLabel={false}
        />

        {/* CONTENT */}
        <Card shadow="sm" padding={24}>
          {showReview ? renderReview() : renderStep()}
        </Card>

        {/* NAVIGATION BUTTONS */}
         {/* NAVIGATION BUTTONS */}
         {!showReview && (
           <Row gap={12} justify="between">
             <Button
               variant="ghost"
               onClick={props.onBack}
               disabled={props.currentStep === 1}
             >
               Back
             </Button>
             <Button
               variant="primary"
               onClick={() => {
                 if (props.currentStep === props.totalSteps) {
                   setShowReview(true);
                 } else {
                   props.onNext();
                 }
               }}
                disabled={
                  props.currentStep === 1 &&
                  (props.name.trim().length === 0 ||
                    props.email.trim().length === 0 ||
                    props.nameError !== '' ||
                    props.emailError !== '')
                }
             >
               {props.currentStep === props.totalSteps ? 'Review' : 'Next'}
             </Button>
           </Row>
         )}

         {/* SUBMIT BUTTON (on review screen) */}
         {showReview && (
           <Stack direction="horizontal" gap={12} justify="between">
             <Button
               variant="ghost"
               onClick={() => setShowReview(false)}
             >
               Back to Editing
             </Button>
             <Button
               variant="primary"
               onClick={props.onSubmit}
             >
               Submit Survey
             </Button>
           </Stack>
         )}
      </Stack>
    </Container>
  );
}
// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

