import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  tasks: Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>;
  columns: Array<{ id: string; name: string }>;
  onTaskMove: (taskId: string, column: string) => void;
  onTaskCreate: (column: string, title: string, priority: 'low' | 'medium' | 'high') => void;
  onTaskEdit: (taskId: string, title: string, priority: 'low' | 'medium' | 'high', dueDate?: string) => void;
  addingTaskColumn: string | null;
  onAddTaskStart: (columnId: string) => void;
  onAddTaskCancel: () => void;
  editingTaskId: string | null;
  onEditTaskStart: (taskId: string) => void;
  onEditTaskCancel: () => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const validTasks = props.tasks || [];
  const validColumns = props.columns || [];
  // Ensure tasks have required fields with defaults
  const initialTasks = validTasks.map((t) => ({
    id: t.id || `task-${Date.now()}-${Math.random()}`,
    title: t.title || 'Untitled',
    priority: t.priority || 'medium',
    assignee: t.assignee || '',
    column: t.column || 'todo',
    dueDate: t.dueDate,
  }));
  const [tasks, setTasks] = useState(initialTasks);
  const [addingTaskColumn, setAddingTaskColumn] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');
  // Listen for real-time task updates from other team members
  useEffect(() => {
    if (taskChanged.latest) {
      setTasks((prev) => {
        const updated = [...prev];
        const idx = updated.findIndex((t) => t.id === taskChanged.latest?.task?.id);
        if (taskChanged.latest.action === 'delete' && idx >= 0) {
          updated.splice(idx, 1);
        } else if (taskChanged.latest.action === 'move' || taskChanged.latest.action === 'edit' || taskChanged.latest.action === 'create') {
          const incomingTask = taskChanged.latest.task;
          if (incomingTask?.id) {
            if (idx >= 0) {
              updated[idx] = {
                id: updated[idx].id,
                title: incomingTask.title || updated[idx].title,
                priority: incomingTask.priority || updated[idx].priority,
                assignee: incomingTask.assignee ?? updated[idx].assignee,
                column: incomingTask.column || updated[idx].column,
                dueDate: incomingTask.dueDate,
              };
            } else {
              updated.push({
                id: incomingTask.id,
                title: incomingTask.title || 'Untitled',
                priority: incomingTask.priority || 'medium',
                assignee: incomingTask.assignee || '',
                column: incomingTask.column || 'todo',
                dueDate: incomingTask.dueDate,
              });
            }
          }
        }
        return updated;
      });
    }
  }, [taskChanged.latest]);

  const handleTaskMove = useCallback((taskId: string, column: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column } : t)));
    taskUpdate({ action: 'move', taskId, data: { column } });
  }, [taskUpdate]);

  const handleTaskCreate = useCallback((column: string, title: string, priority: 'low' | 'medium' | 'high') => {
    const newTaskId = `task-${Date.now()}`;
    const newTask = { id: newTaskId, title, priority, assignee: '', column, dueDate: undefined };
    setTasks((prev) => [...prev, newTask]);
    setAddingTaskColumn(null);
    taskUpdate({ action: 'create', taskId: newTaskId, data: { column } });
  }, [taskUpdate]);

  // Ensure columns have required fields with defaults
  const normalizedColumns = validColumns.map((c) => ({
    id: c.id || 'unknown',
    name: c.name || 'Unnamed',
  }));

  const handleTaskEdit = useCallback((taskId: string, title: string, priority: 'low' | 'medium' | 'high', dueDate?: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title, priority, dueDate } : t)));
    taskUpdate({ action: 'edit', taskId, data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo', title, priority, dueDate } as any });
    setEditingTaskId(null);
  }, [taskUpdate, tasks]);

  return {
    tasks,
    columns: normalizedColumns,
    onTaskMove: handleTaskMove,
    onTaskCreate: handleTaskCreate,
    onTaskEdit: handleTaskEdit,
    addingTaskColumn,
    onAddTaskStart: setAddingTaskColumn,
    onAddTaskCancel: () => setAddingTaskColumn(null),
    editingTaskId,
    onEditTaskStart: setEditingTaskId,
