// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const [newTaskForms, setNewTaskForms] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high' }>>({});
  const [editForms, setEditForms] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high'; dueDate?: string }>>({});

  const handleAddTaskChange = (columnId: string, title: string, priority: 'low' | 'medium' | 'high') => {
    setNewTaskForms((prev) => ({ ...prev, [columnId]: { title, priority } }));
  };

  const handleEditTaskChange = (taskId: string, title: string, priority: 'low' | 'medium' | 'high', dueDate?: string) => {
    setEditForms((prev) => ({ ...prev, [taskId]: { title, priority, dueDate } }));
  };

  const handleCreateTask = (columnId: string) => {
    const form = newTaskForms[columnId];
    if (form?.title.trim()) {
      props.onTaskCreate(columnId, form.title, form.priority);
      setNewTaskForms((prev) => {
        const updated = { ...prev };
        delete updated[columnId];
        return updated;
      });
      props.onAddTaskCancel();
    }
  };

  const handleSaveEditTask = (taskId: string) => {
    const form = editForms[taskId];
    if (form?.title.trim()) {
      props.onTaskEdit(taskId, form.title, form.priority, form.dueDate);
      setEditForms((prev) => {
        const updated = { ...prev };
        delete updated[taskId];
        return updated;
      });
    }
  };

  const validTasks = props.tasks || [];
  const validColumns = props.columns || [];
  const totalTasks = validTasks.length;
  const completedTasks = validTasks.filter((t) => t.column === 'done').length;
  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16}>
