            const columnTasks = validTasks.filter((t) => t.column === col.id);
            return (
              <Box key={col.id} style={{ flex: '0 1 320px' }}>
                <Stack gap={12}>
                  {/* COLUMN HEADER */}
                  <Card padding={12} shadow="none" border={false}>
                    <Row gap={8} justify="between" align="center">
                      <Stack gap={4} direction="horizontal" align="center">

                  {/* TASK CARDS */}
                  <Stack gap={8}>
                    {columnTasks.map((task) => {
                      const isEditing = props.editingTaskId === task.id;
                      const editForm = editForms[task.id];
                      return isEditing ? (
                        <Card key={task.id} padding={12} shadow="sm">
                          <Stack gap={8}>
                            <Input
                              label="Task title"
                              placeholder="Enter task title..."
                              value={editForm?.title || task.title}
                              onChange={(val) => handleEditTaskChange(task.id, val, editForm?.priority || task.priority, editForm?.dueDate || task.dueDate)}
                            />
                            <Select
                              label="Priority"
                              value={editForm?.priority || task.priority}
                              onChange={(val) => handleEditTaskChange(task.id, editForm?.title || task.title, val as 'low' | 'medium' | 'high', editForm?.dueDate || task.dueDate)}
                              options={[
                                { value: 'low', label: 'Low' },
                                { value: 'medium', label: 'Medium' },
                                { value: 'high', label: 'High' },
                              ]}
                            />
                            <Input
                              label="Due date (optional)"
                              type="text"
                              placeholder="YYYY-MM-DD"
                              value={editForm?.dueDate || task.dueDate || ''}
                              onChange={(val) => handleEditTaskChange(task.id, editForm?.title || task.title, editForm?.priority || task.priority, val || undefined)}
                            <Row gap={8} justify="end">
                              <Button variant="ghost" size="sm" onClick={() => props.onEditTaskCancel()}>Cancel</Button>
                              <Button variant="primary" size="sm" onClick={() => handleSaveEditTask(task.id)}>Save</Button>
                            </Row>
                          </Stack>
                        </Card>
                      ) : (
                        <Card key={task.id} padding={12} shadow="sm" role="article" aria-label={`Task: ${task.title}`}>
                          <Stack gap={8}>
                            {/* TASK TITLE - Double-click or edit button to edit */}
                            <Box as={Clickable} onDoubleClick={() => props.onEditTaskStart(task.id)} style={{ cursor: 'text' }} tabIndex={0} role="button" aria-label={`Task title: ${task.title}. Double-click to edit.`}>
                              <Text variant="body" weight="medium">{task.title}</Text>
                            </Box>

                            <Button
                              variant="ghost"
                              size="xs"
                              onClick={() => props.onEditTaskStart(task.id)}
                              aria-label="Edit task details"
                            >
                              Edit
                            </Button>

                            {/* PRIORITY BADGE */}
                            <Row gap={8} align="center">
                              <Badge
                                variant={
                                  task.priority === 'high'
                                    ? 'error'
                                    : task.priority === 'medium'
                                      ? 'warning'
                                      : 'success'
                                }
                                size="sm"
                                aria-label={`Priority: ${task.priority}`}
                              >
                                {task.priority}
                              </Badge>
                            </Row>

                            {/* ASSIGNEE & DUE DATE */}
                            {(task.assignee || task.dueDate) && (
                              <Row gap={8} align="center">
                                {task.assignee && <Avatar name={task.assignee} size="sm" />}
                                {task.dueDate && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" title={`Due date: ${task.dueDate}`} aria-label={`Due date: ${task.dueDate}`}>📅 {task.dueDate}</Text>}
                              </Row>
                            )}

                            {/* MOVE DROPDOWN */}
                            <Dropdown
                              trigger={<Button variant="ghost" size="xs" aria-label="Move task to another column">Move</Button>}
                              options={validColumns
                                .filter((c) => c.id !== col.id)
                                .map((c) => ({ value: c.id, label: c.name }))}
                              value=""
                              onChange={(columnId) => props.onTaskMove(task.id, columnId)}
                              placement="bottom-end"
                            />
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {/* ADD TASK FORM */}
                  {/* ADD TASK FORM */}
                  {props.addingTaskColumn === col.id ? (
                    <Card padding={12} shadow="sm" border={true}>
                      <Stack gap={8}>
                        <Input
                          label={`Task title (${col.name})`}
                          placeholder="Enter task title..."
                          value={newTaskForms[col.id]?.title || ''}
                          onChange={(val) => handleAddTaskChange(col.id, val, newTaskForms[col.id]?.priority || 'medium')}
                        />
                        <Select
                          label="Priority"
                          value={newTaskForms[col.id]?.priority || 'medium'}
                          onChange={(val) => handleAddTaskChange(col.id, newTaskForms[col.id]?.title || '', val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap={8} justify="end">
                          <Button variant="ghost" size="sm" onClick={() => props.onAddTaskCancel()}>Cancel</Button>
                          <Button variant="primary" size="sm" onClick={() => handleCreateTask(col.id)}>Create</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
