  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  return {
    product: props.product,
    quantity,
    setQuantity,
    onAddToCart: handleAddToCart,
    activeTab,
    setActiveTab,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const maxStock = props.product.stock || 0;
  const isOutOfStock = maxStock === 0;
  const isLowStock = maxStock > 0 && maxStock < 10;

  const handleQuantityChange = useCallback((newQty: number) => {
    const clamped = Math.max(1, Math.min(newQty, maxStock));
    props.setQuantity(clamped);
  }, [maxStock, props]);

  const handleIncrement = useCallback(() => {
    handleQuantityChange(props.quantity + 1);
  }, [props.quantity, handleQuantityChange]);

  const handleDecrement = useCallback(() => {
    handleQuantityChange(props.quantity - 1);
  }, [props.quantity, handleQuantityChange]);

  return (
    <Container maxWidth='xl' padding={24}>
      <Stack gap={24}>
        {/* TOP SECTION: Product image, title, price, rating, stock */}
        <Stack direction='horizontal' gap={24} align='start'>
          {/* Product Image Placeholder */}
          <Box
            background='var(--ggui-color-primary-100, #e0f2fe)'
            borderRadius='var(--ggui-shape-radius-lg, 12px)'
            padding={24}
            style={{ minWidth: '300px', maxWidth: '400px', aspectRatio: '1 / 1', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align='center' gap={8}>
              <Icon name='image' size={48} color='var(--ggui-color-primary-600, #0284c7)' />
              <Text variant='label' align='center' color='var(--ggui-color-primary-600, #0284c7)'>
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap={16} style={{ flex: 1 }}>
            <Stack gap={8}>
              <Heading level={2}>{props.product.name || 'Product Name'}</Heading>

              {/* Price */}
              <Heading level={3} color='var(--ggui-color-primary-600, #0284c7)'>
                {props.product.currency || '$'}{props.product.price?.toFixed(2) || '0.00'}
              </Heading>

              {/* Rating Stars */}
              <Stack direction='horizontal' gap={8} align='center'>
                <Stack direction='horizontal' gap={2}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <Icon
                      key={star}
                      name={star <= Math.round(props.product.rating || 0) ? 'star-filled' : 'star'}
                      size={16}
                      color={star <= Math.round(props.product.rating || 0) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}
                    />
                  ))}
                </Stack>
                <Text variant='bodySmall' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                  {props.product.rating ? `${props.product.rating.toFixed(1)} (${props.product.reviewCount || 0} reviews)` : 'No ratings'}
                </Text>
              </Stack>

              {/* Stock Status */}
               <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'primary'}>
                {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
              </Badge>
            </Stack>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: Tabs */}
        <Tabs
          variant='line'
          size='md'
          activeKey={props.activeTab}
          onChange={props.setActiveTab}
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                <Stack gap={8} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  <Text variant='body'>{props.product.description || 'No description available.'}</Text>
                </Stack>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Stack gap={12} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  {Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'name', header: 'Specification', width: '40%' },
                        { key: 'value', header: 'Value', width: '60%' },
                      ]}
                       data={props.product.specifications.map((spec: any, idx: number) => ({
                         id: `spec-${idx}`,
                         name: typeof spec === 'object' ? spec.key || `Spec ${idx + 1}` : `Spec ${idx + 1}`,
                         value: typeof spec === 'object' ? spec.value || '-' : spec,
                       }))}
                      striped
                    />
                  ) : (
                    <Text variant='body' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                      No specifications available.
                    </Text>
                  )}
                </Stack>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Stack gap={12} style={{ paddingTop: 'var(--ggui-spacing-4, 16px)' }}>
                  {Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
                    <Stack gap={12}>
                      {props.product.reviews.map((review: any, idx: number) => (
                        <Card key={idx} padding={16} shadow='sm'>
                          <Stack gap={8}>
                            <Row gap={8} align='center' justify='between'>
                              <Text variant='label' weight='semibold'>
                                {typeof review === 'object' ? review.author || `Reviewer ${idx + 1}` : `Reviewer ${idx + 1}`}
                              </Text>
                              <Stack direction='horizontal' gap={2}>
                                {[1, 2, 3, 4, 5].map((star) => (
                                  <Icon
                                    key={star}
                                     name={star <= (typeof review === 'object' && review.rating ? Math.round(review.rating) : 5) ? 'star-filled' : 'star'}
                                    size={14}
                                    color={
                                      star <= (typeof review === 'object' && review.rating ? Math.round(review.rating) : 5)
                                        ? 'var(--ggui-color-warning-500, #f59e0b)'
                                        : 'var(--ggui-color-outline, #d4d4d8)'
                                    }
                                  />
                                ))}
                              </Stack>
                            </Row>
                            <Text variant='bodySmall'>
                              {typeof review === 'object' ? review.text || review.content || 'No text provided.' : review}
                            </Text>
                            {typeof review === 'object' && review.date && (
                              <Text variant='caption' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                                {new Date(review.date).toLocaleDateString()}
                              </Text>
                            )}
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  ) : (
                    <Text variant='body' color='var(--ggui-color-onSurfaceVariant, #52525b)'>
                      No reviews yet.
                    </Text>
                  )}
                </Stack>
              ),
            },
          ]}
        />

        {/* BOTTOM SECTION: Quantity selector and Add to Cart */}
        <Stack direction='horizontal' gap={16} align='center'>
          {/* Quantity Selector */}
          <Stack direction='horizontal' gap={8} align='center'>
            <Text variant='label'>Quantity:</Text>
            <Button
              variant='outline'
              size='sm'
              onClick={handleDecrement}
              disabled={props.quantity <= 1}
            >
              −
            </Button>
            <Box
              style={{
                width: '40px',
                height: '40px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              }}
            >
              <Text variant='label'>{props.quantity}</Text>
            </Box>
            <Button
              variant='outline'
              size='sm'
              onClick={handleIncrement}
              disabled={props.quantity >= maxStock}
            >
              +
            </Button>
          </Stack>

          <Spacer size='flex' />

          {/* Add to Cart Button */}
          <Button
            variant='primary'
            size='lg'
            onClick={() => props.onAddToCart()}
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

