/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  title: string;
  participantCount: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  typingUser: { sender?: string } | null;
  onSendMessage: (text: string) => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages);
  const [typingUser, setTypingUser] = useState<{ sender?: string } | null>(null);

  // Wire hooks
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // Append incoming messages to the list
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Update typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser({ sender: typing.latest.sender });
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  const handleSendMessage = useCallback((text: string) => {
    sendMessage({
      text,
      timestamp: new Date().toISOString(),
    });
  }, [sendMessage]);

  return {
    title: props.title,
    participantCount: props.participantCount,
    messages: allMessages,
    typingUser,
    onSendMessage: handleSendMessage,
  };
}
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [props.messages, props.typingUser]);

  const handleSend = () => {
    if (inputText.trim()) {
      props.onSendMessage(inputText.trim());
      setInputText('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={16} style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
        {/* HEADER */}
        <Card padding={16} shadow="sm">
          <Stack direction="horizontal" gap={16} justify="between" align="center">
            <Stack direction="horizontal" gap={12} align="center">
              <Heading level={2}>{props.title}</Heading>
              <Badge variant="primary" size="sm">
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Badge>
            </Stack>
          </Stack>
        </Card>

        {/* MESSAGE LIST */}
        <Card
          padding={16}
          shadow="sm"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {props.messages.length === 0 ? (
            <Box
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                height: '100%',
                color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
              }}
            >
              <Text variant="body">No messages yet. Start the conversation!</Text>
            </Box>
          ) : (
            props.messages.map((msg, idx) => {
              const isCurrentUser = msg.sender === props.participantCount > 1 ? 'currentUser' : '';
              const isOwnMessage = msg.sender !== props.title;
              return (
                <Box
                  key={idx}
                  style={{
                    display: 'flex',
                    flexDirection: isOwnMessage ? 'row' : 'row-reverse',
                    justifyContent: isOwnMessage ? 'flex-end' : 'flex-start',
                    gap: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  <Card
                    padding={12}
                    shadow="none"
                    border={false}
                    style={{
                      maxWidth: '60%',
                      backgroundColor: isOwnMessage
                        ? 'var(--ggui-color-primary-600, #0284c7)'
                        : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                    }}
                  >
                    {msg.sender && !isOwnMessage && (
                      <Text
                        variant="label"
                        style={{
                          color: isOwnMessage
                            ? '#ffffff'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                        }}
                      >
                        {msg.sender}
                      </Text>
                    )}
                    <Text
                      variant="body"
                      style={{
                        color: isOwnMessage ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)',
                      }}
                    >
                      {msg.text}
                    </Text>
                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        style={{
                          color: isOwnMessage
                            ? 'rgba(255,255,255,0.7)'
                            : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                          marginTop: 'var(--ggui-spacing-1, 4px)',
                        }}
                      >
                        {new Date(msg.timestamp).toLocaleTimeString([], {
                          hour: '2-digit',
                          minute: '2-digit',
                        })}
                      </Text>
                    )}
                  </Card>
                </Box>
              );
            })
          )}

          {/* TYPING INDICATOR */}
          {props.typingUser && (
            <Box
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-1, 4px)',
              }}
            >
              <Card
                padding={12}
                shadow="none"
                border={false}
                style={{
                  backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                }}
              >
                <Text
                  variant="body"
                  style={{{
                    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                  }}}
                >
                  {props.typingUser.sender || 'Someone'} is typing
                  <span
                    style={{
                      animation: 'pulse 1.5s ease-in-out infinite',
                    }}
                  >
                    ....
                  </span>
                </Text>
              </Card>
            </Box>
          )}

          <div ref={messagesEndRef} />
        </Card>

        {/* INPUT AREA */}
        <Stack gap={12}>
          <TextArea
            label="Message"
            placeholder="Type your message... (Shift+Enter for new line)"
            value={inputText}
            onChange={setInputText}
            onKeyDown={handleKeyDown}
            rows={3}
          />
          <Button
            variant="primary"
            fullWidth
            onClick={handleSend}
            disabled={!inputText.trim()}
          >
            Send Message
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

