// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState(new Date().toLocaleTimeString());
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const [isLoading, setIsLoading] = useState(!props.stocks || props.stocks.length === 0);
  const [error, setError] = useState<string | null>(null);
  const updateTimeoutRef = useRef<Record<string, NodeJS.Timeout>>({});

  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  // Validate stock data
  const hasValidationErrors = useMemo(() => {
    return displayStocks.some((stock) => !stock.symbol || stock.price === undefined);
  }, [displayStocks]);

  // Merge price updates into displayStocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const { symbol, price, change, changePercent } = priceUpdate.latest;
      if (symbol) {
        setDisplayStocks((prev) =>
          prev.map((stock) => {
            if (stock.symbol === symbol) {
              return { ...stock, price, change, changePercent };
            }
            return stock;
          })
        );

        // Trigger highlight animation
        setUpdatingSymbols((prev) => new Set([...prev, symbol]));

        // Clear timeout if already set
        if (updateTimeoutRef.current[symbol]) {
          clearTimeout(updateTimeoutRef.current[symbol]);
        }

        // Remove highlight after animation duration
        updateTimeoutRef.current[symbol] = setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const updated = new Set(prev);
            updated.delete(symbol);
            return updated;
          });
        }, 600);
      }

      // Update timestamp
      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, [priceUpdate.latest]);

  // Handle stream errors
  useEffect(() => {
    if (priceUpdate.latest?.symbol === undefined && priceUpdate.all.length > 0) {
      // If we have stream events but no valid symbol, it might indicate a connection issue
    }
  }, [priceUpdate]);

  // Merge initial stocks on prop change
  useEffect(() => {
    setDisplayStocks(props.stocks);
    setIsLoading(false);
  }, [props.stocks]);

  const displayStocksWithAnimation = useMemo(() => {
    return displayStocks.map((stock) => ({
      ...stock,
      isUpdating: updatingSymbols.has(stock.symbol || ''),
    }));
  }, [displayStocks, updatingSymbols]);

  const currentMarketStatus = marketStatus.latest?.status || null;

  return {
    stocks: props.stocks,
    displayStocks: displayStocksWithAnimation,
    lastUpdated,
    marketStatus: currentMarketStatus,
    isLoading,
    error,
    hasValidationErrors,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // Show loading state
  if (props.isLoading) {
    return (
      <Container maxWidth="2xl" padding={24}>
        <Stack gap={24} align="center" justify="center">
          <Spinner size={40} color="var(--ggui-color-primary-600, #0284c7)" />
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Loading market data....
          </Text>
        </Stack>
      </Container>
    );
  }

  // Show empty state
  if (!props.stocks || props.stocks.length === 0) {
    return (
      <Container maxWidth="2xl" padding={24}>
        <Stack gap={24} align="center" justify="center">
          <Alert variant="info" title="No Data">
            No stocks available. Please check back later or ensure stocks have been loaded.
          </Alert>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="2xl" padding={24}>
      <Stack gap={24}>
        {/* Validation error alert */}
        {props.hasValidationErrors && (
          <Alert variant="warning" title="Data Validation Warning" closable>
            Some stocks have missing required fields (symbol or price). Please verify the data.
          </Alert>
        )}

        {/* HEADER */}
        <Stack gap={2} align="center" justify="between" direction="horizontal">
          <Heading level={1}>Market Watch</Heading>
          <Stack gap={8} direction="horizontal" align="center">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated: {props.lastUpdated}
            </Text>
            {props.marketStatus && (
              <Badge variant={props.marketStatus === 'open' ? 'success' : 'warning'} size="sm">
                {props.marketStatus === 'open' ? 'Market Open' : props.marketStatus === 'closed' ? 'Market Closed' : props.marketStatus}
              </Badge>
            )}
          </Stack>
        </Stack>

        {/* STOCK GRID */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: 'var(--ggui-spacing-4, 16px)',
        }}>
          {props.displayStocks.map((stock) => {
            const isPositive = (stock.changePercent || 0) >= 0;
            const changeColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const borderColor = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';

            return (
              <Card
                key={stock.symbol}
                padding={16}
                shadow="sm"
                radius="lg"
                style={{
                  borderLeft: `3px solid ${borderColor}`,
                  animation: stock.isUpdating ? 'ggui-flash 600ms ease-out' : 'none',
                  transition: 'all 200ms ease-in-out',
                  backgroundColor: stock.isUpdating
                    ? isPositive
                      ? 'var(--ggui-color-success-50, #f0fdf4)'
                      : 'var(--ggui-color-error-50, #fef2f2)'
                    : 'var(--ggui-color-surface, #ffffff)',
                }}
              >
                <Stack gap={8}>
                  {/* Ticker and Company */}
                  <Stack gap={2}>
                    <Text
                      size="lg"
                      weight="bold"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {stock.symbol}
                    </Text>
                    <Text
                      variant="bodySmall"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {stock.name}
                    </Text>
                  </Stack>

                  {/* Price */}
                  <Text
                    size="xl"
                    weight="bold"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    ${(stock.price || 0).toFixed(2)}
                  </Text>

                  {/* Change and Change Percent */}
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text
                      variant="label"
                      color={changeColor}
                    >
                      {isPositive ? '▲' : '▼'} {(stock.change || 0).toFixed(2)}
                    </Text>
                    <Text
                      variant="label"
                      color={changeColor}
                    >
                      ({(stock.changePercent || 0).toFixed(2)}%)
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>

      {/* Flash animation keyframes */}
      <style>{`
        @keyframes ggui-flash {
          0% { opacity: 1; }
          50% { opacity: 0.6; }
          100% { opacity: 1; }
        }
      `}</style>
    </Container>
  );
}
}

