// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  currentStep: number;
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onAvatarSelect: (avatar: string) => void;
  onRoleChange: (value: string) => void;
  onEmailNotificationsChange: (value: boolean) => void;
  onThemeChange: (value: boolean) => void;
  onNext: () => void;
  onBack: () => void;
  onComplete: () => void;
  errors: { name?: string; email?: string };
  roleOptions: string[];
  avatarOptions: string[];
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications !== false);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  const complete = useAction<ActionCompletePayload>('complete');

  // Validation helpers
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: { name?: string; email?: string } = {};
    if (!name.trim()) newErrors.name = 'Name is required';
    if (!email.trim()) newErrors.email = 'Email is required';
    else if (!validateEmail(email)) newErrors.email = 'Invalid email format';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
        setErrors({});
      }
    } else if (currentStep === 2) {
      setCurrentStep(3);
    }
  }, [currentStep, name, email]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme: theme === 'dark' ? 'dark' : 'light',
    });
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  return {
    currentStep,
    name,
    email,
    avatar,
    role,
    emailNotifications,
    theme,
    onNameChange: setName,
    onEmailChange: setEmail,
    onAvatarSelect: setAvatar,
    onRoleChange: setRole,
    onEmailNotificationsChange: setEmailNotifications,
    onThemeChange: (isDark: boolean) => setTheme(isDark ? 'dark' : 'light'),
    onNext: handleNext,
    onBack: handleBack,
    onComplete: handleComplete,
    errors,
    roleOptions: props.roleOptions,
    avatarOptions: props.avatarOptions,
  };
}

